import{_ as t,H as r,f as n,i as o}from"./chunks/framework.DLd0CbzH.js";const u=JSON.parse('{"title":"赞比亚","description":"赞比亚国情资料 — 赞比亚","frontmatter":{"title":"赞比亚","description":"赞比亚国情资料 — 赞比亚"},"headers":[],"relativePath":"mining/zambia/zh/zambia-overview.md","filePath":"mining/zambia/zh/zambia-overview.md"}'),s={name:"mining/zambia/zh/zambia-overview.md"};function g(a,p,i,e,l,m){return r(),n("div",null,[...p[0]||(p[0]=[o('<h1 id="赞比亚" tabindex="-1">赞比亚 <a class="header-anchor" href="#赞比亚" aria-label="Permalink to &quot;赞比亚&quot;">​</a></h1><div class="reading-prose"><p><strong>赞比亚共和国</strong></p><p><strong>【国</strong>** **<strong>名】</strong></p><p>赞比亚共和国（The Republic of Zambia）。</p><p>**【面 **** **<strong>积】</strong></p><p>752614平方公里。</p><p><strong>【人</strong>** **** 口】**</p><p>1940万（2022），大多属班图语系黑人。有73个民族，奔巴族为最大部族，约占全国人口的33.6%。官方语言为英语，另有31种部族语言。80%的人信奉基督教和天主教。</p><p>**【首 **** **<strong>都】</strong></p><p>卢萨卡（Lusaka），人口310万。海拔1280米，10月最热，日平均最高气温31℃，最低18℃；7月最凉，日平均最高气温23℃，最低9℃。</p><p><strong>【<strong><strong>主要城市</strong></strong>】</strong></p><p>卢萨卡，赞比亚首都，位于赞中部高原，平均海拔1279米，是赞政治、经济、文化和交通中心。面积360平方公里，气候温和。</p><p>利文斯顿，主要旅游城市，隶属南方省，位于卢萨卡市西南约480公里，距维多利亚大瀑布约10公里。地处赞（比亚）津（巴布韦）边界。殖民时期曾为赞比亚首都。以英国传教士戴维•利文斯顿的名字命名。主要景点有：维多利亚大瀑布、赞津边界桥等。</p><p>铜带省两个主要城市为恩多拉和基特韦，是赞重要的经济中心。</p><p><strong>【国家元首】</strong></p><p>总统哈凯恩德·希奇莱马（Hakainde Hichilema），2021年8月24日就任。</p><p><strong>【重要节日】</strong></p><p>青年节：3月12、13日。非洲解放日：5月25日。独立日：10月24日。</p><p>**【政  **** **<strong>治】</strong></p><p>实行总统内阁制。总统为国家元首、政府首脑兼武装部队总司令，由全民选举产生，任期5年，可连选连任一次。</p><p><strong>【官方网站】</strong></p><p>** **** **<strong><a href="http://www.statehouse.gov.zm" target="_blank" rel="noreferrer">http://www.statehouse.gov.zm</a></strong></p><p><strong>【司法机构】</strong></p><p>由最高法院、高等法院、劳资关系法院、初级法院和地方法庭组成。首席大法官艾琳·曼比利玛（Irene Mambilima）。</p><p><strong>【政</strong>** **<strong>党】</strong></p><p>现有注册政党逾50个</p><p><strong>【<strong><strong>2022经济指标</strong></strong>】</strong></p><p>2022年主要经济指标如下（数据来源为《伦敦经济季评》）：</p><ul><li><p>1.国内生产总值：297.8亿美元。</p></li><li><p>2.人均国内生产总值：1487.9美元。</p></li><li><p>3.经济增长率：4.7%。</p></li><li><p>4.失业率：6.1%</p></li><li><p>5.通货膨胀率：11%。</p></li><li><p>6.经济增长率：4.7%。</p></li><li><p>7.外汇储备：30亿美元。</p></li></ul><p><strong>【资</strong>** **** 源】**</p><p>自然资源丰富，以铜为主。铜蕴藏量2000万吨，约占世界铜总蕴藏量的2.8%，素有“铜矿之国”之称。钴是铜的伴生矿，储量约35万吨，居世界第二位。此外还有铅、镉、硒、镍、铁、金、银、锌、锡、铀、绿宝石、水晶、钒、石墨、云母等矿物。全国森林覆盖率为45%。</p><p>赞比亚矿产资源非常丰富，以铜为主，是世界第四大产铜国，被誉为“铜矿之国”。已探明铜蕴藏量1900万吨，约占世界总蕴藏量的6%，人均占有量位居世界第一。其他有色金属类矿藏有钴、锌、铅、镍、铂、锰、锡和铁等。其中，钴作为铜的伴生矿物，赞储量居非洲第二。已探明的铅锌矿总储量约为496万吨，其品位含铅15%，含锌25%，是世界上铅锌品位和储量最丰富的地区之一。铁储量较为丰富，已探明储量约9亿吨。非金属矿产资源有石灰石、磷酸盐、钾（钠）长石、硅灰石、大理石、花岗岩和方钠石等。此外，赞比亚还有多种宝石。除钻石外，还有祖母绿、黄宝石、紫水晶、绿玉石、孔雀石、石榴石、电气石等。其中，祖母绿产量占世界总产量的20%以上。</p><p><strong>【<strong><strong>税</strong></strong> <strong><strong>赋</strong></strong>】</strong></p><p>赞比亚财政部负责制定国家税收政策，根据宏观经济发展的需要，每年对税率标准进行一定调整。赞比亚税务局（Zambia Revenue Authority，简称ZRA）是政府管理和征收各类税收（含关税）的主管机构。</p><p>主要的税种包括直接税（公司所得税、个人所得税和基于个人收入的其它税收等）、关税、消费税、增值税、矿产资源税和资产转移税等。具体税率请参见赞税务局网站<a href="https://www.zra.org.zm/tax-information/%E3%80%82" target="_blank" rel="noreferrer">https://www.zra.org.zm/tax-information/。</a></p><p><strong>【<strong><strong>支付方式</strong></strong>】</strong></p><p>在赞比亚主要使用现金支付。国际通行的银行卡可以在主要银行机构、大型酒店和商场使用。</p><p><strong>【<strong><strong>银行及金融</strong></strong>】</strong></p><p>赞比亚银行（Bank of Zambia）是赞比亚中央银行，也是国家金融最高管理机构，成立于1964年。该银行首要职能为发行法定货币，维持货币稳定；制定金融政策，保证健全的金融体系；充当银行业经营者和金融顾问；管理和监督各类商业银行。</p><p>目前赞比亚有17家商业银行（包括外资银行和本土银行）。英国渣打银行、南非标准银行、美国花旗银行等均在赞设置了分支机构。</p><p>赞比亚中国银行于1997年设行，是进入非洲的第一家中资金融机构，也是赞唯一一家中资银行。赞比亚中国银行持有子行牌照，在卢萨卡和基特韦各设有一个分行，注册资本达到1亿美元，能够提供全牌照的金融服务，2015年还成为中赞两国中央银行指定的人民币清算行。</p><p>赞比亚其他主要金融机构包括赞比亚发展银行（Development Bank of Zambia），国家储蓄及信贷银行（National Savings and Credit Bank）、房屋信贷互助会、租赁公司和外币兑换所，以及英国保诚集团等9家保险公司。</p><p><strong>【<strong><strong>医疗保险</strong></strong>】</strong></p><p>首都卢萨卡有全国最大的公立医院：赞比亚大学教学医院（UTH）紧急救助电话：00260-211-251451。援赞医疗队所在的利维·姆瓦纳瓦萨医院和援赞军医组所在的三军总医院也能为患重大疾病的中国公民提供紧急救助。</p><p>在铜带省基特韦市，赞中经贸合作区所属的中赞友谊医院拥有中国医生和一定的医疗条件。当地保险业有一定规模。中国公民和企业可自行选择保险经纪公司购买人身或医疗保险。</p><p><strong>【旅</strong>** <strong><strong>游</strong></strong> **<strong>业】</strong></p><p>有世界著名的维多利亚瀑布和19个国家级野生动物园，其中卡富埃国家公园占地面积最大。赞还辟有32个狩猎管理区。游客人数保持增长势头。2013年8月，赞比亚和津巴布韦联合举办了第20届世界旅游组织大会。</p><p>**【军  **** ****事】 **</p><p>正规军3.5万人，其中陆军2.1万人、空军约6000人，另有国民服务队（准军事部队）8000人、警察2.5万人。武器装备主要来自中国、前苏联、美国、意大利、加拿大、德国等。</p><p><strong>【文化教育】</strong></p><p>实行9年制普及义务教育。成人识字率约为75%。目前全国有基础学校8801所，高中690所，技术教育和职业培训院校268所，大学3所，即赞比亚大学、铜带省大学和穆隆古希大学。约95%的适龄儿童能入学，其中有20%可继续升入中学，20～24岁的青年中有2%左右能享受高等教育。赞比亚政府在各地设有文化村或文化中心，以保留和发展民间传统文化和艺术。近年来，政府利用外国援助，不断加大对教育部门的资金投入。</p><p><strong>【同中国的关系】</strong></p><p>中国与赞比亚于1964年10月29日建交，赞是南部非洲第一个与中国建交的国家。两国传统友谊深厚，双边友好合作关系不断发展。</p><p>1967年以来，中国承担了坦赞铁路、公路、玉米面厂、纺织厂、打井供水等共70余个项目。坦赞铁路是中国最大的援外成套项目之一。在中非合作论坛框架内，我方为赞方援建了体育场、医院、学校、农技示范中心、疟疾防治中心、小水电站、太阳能、打井等多个项目。</p><p>**1.**<strong>地理位置</strong></p><ul><li>1.1.1 赞比亚地处非洲中南部内陆，无出海口，周围与8个国家接壤。东接马拉维、莫桑比克，南接津巴布韦、博茨瓦纳、纳米比亚，西邻安哥拉，北靠刚果（金）及坦桑尼亚。</li></ul><p>赞比亚国土面积75.26万平方公里，大部分地区海拔1000-1500米。地势东北高、西南低，其东北边境的马芬加山（Mafinga Hills）为全国最高峰，海拔2164米。</p><p>赞比亚所属时区为东2时区，比北京晚6个小时，不采用夏令时。</p><p><strong>2.行政区划</strong></p><p>【行政区划】赞比亚全国下设10省103区。其中姆钦嘎省（Muchinga）是第五任总统萨塔当选后于2011年新设。</p><p>【首都】卢萨卡（Lusaka），位于赞比亚中部高原，平均海拔1280 米，是国家政治、经济、文化和交通中心，人口310万。</p><p>【主要经济中心城市】卢萨卡（Lusaka）、恩多拉（Ndola）、基特韦（Kitwe）和卡布韦（Kabwe）为主要经济中心城市。</p><p><strong>3.自然资源</strong></p><p>【矿产资源】赞比亚矿产资源非常丰富。有色金属类矿藏有铜、钴、锌、铅、镍、铂、锰、锡、铁和金等。</p><p>赞比亚被誉为“铜矿之国”，已探明铜储量1900万吨，约占世界铜总储量的6%，人均占有量位居世界第一，2019年铜产量约为75万吨。该国的铜矿资源主要集中分布在铜带省和西北省。铜带省的铜矿经过几十年的开发，几乎都由早期的露天开采转为地下开采，并且随着开采深度的增加， 开采难度不断加大。西北省铜矿以露天开采为主，但品位较低。</p><p>钴是铜的伴生矿物，储量约35万吨，2018年赞比亚钴产量为7790吨， 为世界主要产钴国。铅锌矿主要分布在卡布韦，已探明的铅锌矿总储量约为496万吨，其品位含铅15%，含锌25%，是世界上铅锌品位和储量最丰富的地区之一。铁储量较为丰富，已探明储量约9亿吨，矿石品位达50%， 主要分布在中央省和西方省。非金属矿产资源有石灰石、磷酸盐、钾（钠）长石、硅灰石、大理石、花岗岩和方钠石等。</p><p>赞比亚还有多种宝石，包括祖母绿、紫水晶、钻石、孔雀石、石榴石、电气石等。其中，祖母绿产量占世界总产量的20%以上，且透明度高，品质良好。</p><p><strong>4.气候条件</strong></p><p>赞比亚属热带草原气候，温和凉爽，年平均气温在18-20℃之间。全年分三季，5-8月为干凉季，气温在15-27℃，为大部分农作物收获季节；9-11 月为干热季， 气温26-36 ℃；12 月至次年4 月为温湿季， 气温</p><ul><li>26.7-32.2℃，全年雨量集中在该季，北部年降雨量约1400毫米，向南递减至700毫米。</li></ul><p><strong>5.人口分布</strong></p><p>赞比亚人口主要集中在首都卢萨卡、铜带省恩多拉、基特韦、南方省利文斯顿等市，这些城市也是华人华侨的主要聚集地。</p><p>**6.**<strong>政府机构</strong></p><p>赞比亚政府实行总统内阁制。内阁由总统、副总统和30名部长组成。主要部委为：国防部、司法部、财政部、发展规划部、内政部、卫生部、外交部、农业部、渔业与畜牧业部、青年与体育部、商业/贸易与工业部、矿业与矿产发展部、能源部、信息与广播部、劳动与社会保障部、高等教育部、普通教育部、土地/自然资源与环境保护部、地方政府部、社区发展部与社会福利部、酋长与传统事务部、旅游与艺术部、交通与通信部、工程与供应部、住房与基础设施发展部、性别部、总统事务部、水利与环境保护部、国民指导与宗教事务部、副总统办公室部。</p><p>其他重要经济部门包括国家税务局、粮食储备署、赞比亚发展署、赞比亚银行（央行）、能源管理委员会等。</p><p>**7.**<strong>节假日</strong></p><p>赞比亚每年有12天的法定节日，每周一至周五为工作日，实行周六、周日双休。</p><p><strong>铜带省</strong></p><p>铜带省，赞比亚中北部的省，邻民主刚果（扎伊尔）沙巴区。面积3.13万平方公里。人口1,581,221（2000年）。首府恩多拉。大部属非洲中部加丹加高原东段，海拔1，000米以上。</p><p>地表经长期侵蚀割切，形成一系列兀立的山脊和条状凹槽，古老岩层广泛出露。在古砂岩中富藏以铜为主的多金属矿物。热带草原气候，年降水量1，200—1，300毫米。卡富埃河及其支流流贯全境。</p><p>世界闻名的铜带的一部分，矿区自西北向东南断续延伸，长220余公里，宽65公里。除铜外，伴生有丰富的钴、硒、铀、金、银等。有恩昌加、穆富利拉、恩卡纳等大矿和恩多拉、基特韦、钦戈拉、卢安夏等冶炼中心和工业城市。有炼油、机械、水泥、食品等工业。</p><p>全省共分10个县:</p><p>奇利拉隆布韦县 (Chililalombwe District)</p><p>钦戈拉县(Chingola District)</p><p>卡卢卢希县(Kalulushi District)</p><p><strong>基特韦县(Kitwe District)</strong></p><p>卢安夏县(Luanshya District)</p><p>卢富万亚马县 (Lufwanyama District)</p><p>马塞塔县 (Masaita District)</p><p>姆彭戈韦县 (Mpongwe District)</p><p>穆富利拉县(Mufulira District)</p><p><strong>恩多拉县(Ndola District)</strong></p></div>',2)])])}const h=t(s,[["render",g]]);export{u as __pageData,h as default};
